#### Model visualization


::: {.cell filename='prepare lightsource model H11 plot'}

```{.r .cell-code}
H11_data <- 
H11_model_1 |> 
  conditional_values(
    condition = list(Time = seq(0.25, 23.75, by = 0.5), "sex", "photoperiod.state"),
    exclude = c("s(Time,Id)", "s(Id_date)", "s(Time,site)")
    ) |> 
  mutate(across(c(.fitted, .lower_ci, .upper_ci),
                exp_zero_inflated)
  )

H11_data <-
metric_participanthour |> 
  Datetime2Time() |> 
  group_by(sex, Time) |> 
  summarize(
    .groups = "drop_last",
    dawn = dawn |> as.numeric() |> mean(na.rm = TRUE)/3600,
    dusk = dusk |> as.numeric() |> mean(na.rm = TRUE)/3600,
    n = n()
  ) |> 
  mutate(
    photoperiod.state = ifelse(between(Time, dawn, dusk), "day", "night")
  ) |> 
  select(-c(dawn, dusk)) |> 
  left_join(H11_data, by = c("sex", "Time", "photoperiod.state"))

H11_data_phot <- 
H11_data |> 
  number_states(photoperiod.state) |> 
  filter(photoperiod.state == "night") |> 
  group_by(sex, photoperiod.state.count) |> 
  summarize(xmin = min(Time),
            xmax = max(Time),
            .groups = "drop_last") |> 
  mutate(across(c(xmin, xmax), \(x) replace_values(x,
                                                   0.5 ~ 0,
                                                   23.5 ~ 24)))
```
