           replace_when((n < 200 ) ~ NA,
                        lightsource_primary == "Light entering from outside during sleep" ~ NA),
         site = factor(site)
           )

activity_data <- 
hourly_data2 |> 
  ungroup() |> 
  select(site, sex, Id, Time, lzMEDI, Id_date, photoperiod, photoperiod.state, starts_with("act_"), Datetime, lightsource_primary) |> 
  pivot_longer(cols = starts_with("act_"), names_to = "activity", names_prefix = "act_", values_to = "value") |> 
  filter(value, !is.na(lzMEDI)) |>
  distinct(.keep_all = TRUE, site, sex, Time, Id, Datetime, photoperiod.state, activity) |>
  select(-value) |> 
  mutate(
    Id = factor(Id)
  ) |> 
    group_by(Id) |> 
  mutate(AR.start = ifelse(row_number() == 1, TRUE, FALSE)) |> 
  ungroup()

activity_data <-
